#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int minSum = INT_MAX;
        int minIndex = -1;
        for (int i = 0; i < N; i++) {
            int prefixSum = 0;
            int suffixSum = 0;
            for (int j = 0; j <= i; j++) {
                prefixSum += A[j];
            }
            for (int j = i; j < N; j++) {
                suffixSum += A[j];
            }
            if (prefixSum + suffixSum < minSum) {
                minSum = prefixSum + suffixSum;
                minIndex = i;
            }
        }
        printf("%d\n", minIndex + 1);
    }
    return 0;
}

