import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int minSum = Integer.MAX_VALUE;
            int minIndex = -1;
            for (int i = 0; i < N; i++) {
                int prefixSum = 0;
                int suffixSum = 0;
                for (int j = 0; j <= i; j++) {
                    prefixSum += A[j];
                }
                for (int j = i; j < N; j++) {
                    suffixSum += A[j];
                }
                if (prefixSum + suffixSum < minSum) {
                    minSum = prefixSum + suffixSum;
                    minIndex = i;
                }
            }
            System.out.println(minIndex + 1);
        }
    }
}

